    size_t size = 4096;
    void *ptr = mmap(
        NULL, size,
        PROT_READ | PROT_WRITE,
        MAP_PRIVATE | MAP_ANONYMOUS,
        -1, 0);
    if (ptr == MAP_FAILED) {
        perror("mmap");
        return 1;
    }
    int *arr = (int *)ptr;
    int all_zero = 1;
    for (int i = 0; i < 10; i++) {
        if (arr[i] != 0) all_zero = 0;
